mapper.select:
select app_code as appCode from ecm_busi_info
where busi_id in (SELECT busi_id from ecm_busi_recycle)
and app_code=#{appCode}

SELECT info.busi_id, info.busi_no, info.app_code, f.doc_code, info.create_user, info.create_time, info.update_user, info.update_time, info.is_deleted, info.create_user_name, info.update_user_name, info.org_code, info.org_name FROM ecm_busi_info info LEFT JOIN ecm_file_info f ON f.busi_id = info.busi_id
info.is_deleted = 0 AND f.is_deleted = 0
AND info.create_time >= TO_DATE(#{createTimeStart}, 'YYYY-MM-DD HH24:MI:SS') AND info.create_time <= TO_DATE(#{createTimeEnd}, 'YYYY-MM-DD HH24:MI:SS')
AND info.org_code LIKE '%' || #{orgCode} || '%'
AND info.busi_no = #{busiNo}
AND f.doc_code = #{docCode}
AND f.state = #{state}
GROUP BY info.busi_id, info.busi_no, info.app_code, f.doc_code, info.create_user, info.create_time, info.update_user, info.update_time, info.is_deleted, info.create_user_name, info.update_user_name, info.org_code, info.org_name ORDER BY info.create_time ASC

SELECT count(info.busi_id)
FROM ecm_busi_info info

    
        AND info.right_ver = #{rightVer}
    
    
        AND info.app_code = #{appCode}

SELECT info.busi_id, info.busi_no, info.app_code, info.right_ver, info.tree_type, info.create_user, info.create_time, info.update_user, info.update_time, info.is_deleted, info.create_user_name, info.update_user_name, info.org_code, info.org_name, info.status, info.err_no, info.remark FROM ecm_busi_info info where info.busi_id in
#{item}
ORDER BY info.create_time DESC

